import{c as n,Q as t,j as s,m as e}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"Android 原生开发系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"androidNativeLearning/00-写作计划.md","filePath":"androidNativeLearning/00-写作计划.md","lastUpdated":1779789238000}'),o={name:"androidNativeLearning/00-写作计划.md"};function i(l,a,p,r,d,c){return t(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="android-原生开发系列写作计划" tabindex="-1">Android 原生开发系列写作计划 <a class="header-anchor" href="#android-原生开发系列写作计划" aria-label="Permalink to &quot;Android 原生开发系列写作计划&quot;">​</a></h1><blockquote><p>基线版本:<strong>Android 15 (API 35) / Kotlin 2.0 (K2) / Jetpack Compose BOM 1.7+</strong>(2026/05 时点)。 不做&quot;全家桶百科&quot;,不做&quot;Java 老 Android 迁移手册&quot;,不做&quot;跨端选型对比&quot;。</p></blockquote><hr><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>让一个会写代码、但没怎么写过 Android 的人,用 Kotlin + Compose 把一款能上 Play Store 的现代 Android 应用做出来。</strong></p><p>读者画像:已经熟悉一门主流语言(Go / Python / TS / Java 都行),知道什么是面向对象与函数式,但 Android 的印象还停留在 Java + XML + AsyncTask 时代,或者根本没写过 Android。</p><hr><h2 id="统一心智-贯穿-22-章" tabindex="-1">统一心智(贯穿 22 章) <a class="header-anchor" href="#统一心智-贯穿-22-章" aria-label="Permalink to &quot;统一心智(贯穿 22 章)&quot;">​</a></h2><blockquote><p><strong>现代 Android 是一棵被状态驱动重组的 UI 树,挂在单个 Activity 上,被一组 ViewModel 持有状态,被协程驱动副作用。其余 Jetpack 库,都是这棵树的扩展或副作用边界。</strong></p></blockquote><p>这句话压住全场。后面所有章节都是这句话的推论:</p><ul><li><strong>&quot;一棵 UI 树&quot;</strong> → 05/06/07/08/09 篇讲 Compose 怎么写、怎么重组</li><li><strong>&quot;被状态驱动&quot;</strong> → 10 篇 ViewModel + UDF,状态如何流动</li><li><strong>&quot;挂在单 Activity 上&quot;</strong> → 11 篇 Navigation,告别多 Activity / Fragment</li><li><strong>&quot;被协程驱动副作用&quot;</strong> → 04 篇协程与 Flow</li><li><strong>&quot;Jetpack 库是扩展或副作用边界&quot;</strong> → 12-19 篇,DI / 持久化 / 网络 / 系统能力</li></ul><p>如果哪一篇没法挂在这棵树上,这一篇就不该出现。</p><hr><h2 id="_22-章地图" tabindex="-1">22 章地图 <a class="header-anchor" href="#_22-章地图" aria-label="Permalink to &quot;22 章地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智(1 章)</span></span>
<span class="line"><span>  01  现代 Android 的一棵树</span></span>
<span class="line"><span></span></span>
<span class="line"><span>地基(3 章)</span></span>
<span class="line"><span>  02  项目骨架与 Gradle 构建工具链</span></span>
<span class="line"><span>  03  Kotlin 2.0 语言心智</span></span>
<span class="line"><span>  04  协程与 Flow:结构化并发</span></span>
<span class="line"><span></span></span>
<span class="line"><span>UI 一族(5 章)</span></span>
<span class="line"><span>  05  Compose 入口与单 Activity 模型</span></span>
<span class="line"><span>  06  重组、状态与 remember</span></span>
<span class="line"><span>  07  输入控件与 TextField2</span></span>
<span class="line"><span>  08  布局、Modifier 与自适应</span></span>
<span class="line"><span>  09  动画、SharedElement 与 Lookahead</span></span>
<span class="line"><span></span></span>
<span class="line"><span>架构与闭环(5 章)</span></span>
<span class="line"><span>  10  应用架构:ViewModel、UDF 与 UIState</span></span>
<span class="line"><span>  11  Navigation Compose 路由</span></span>
<span class="line"><span>  12  Hilt 依赖注入</span></span>
<span class="line"><span>  13  Room 与 DataStore 持久化</span></span>
<span class="line"><span>  14  Retrofit 与第一个端到端闭环</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统能力(5 章)</span></span>
<span class="line"><span>  15  权限模型与运行时申请</span></span>
<span class="line"><span>  16  后台任务:WorkManager 与前台服务</span></span>
<span class="line"><span>  17  通知与推送通道</span></span>
<span class="line"><span>  18  CameraX、Photo Picker 与 MediaStore</span></span>
<span class="line"><span>  19  系统集成:Intent、AppLinks、Glance Widget</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工程化与发布(3 章)</span></span>
<span class="line"><span>  20  多模块化:app / feature / core / data</span></span>
<span class="line"><span>  21  Compose 性能与启动优化</span></span>
<span class="line"><span>  22  测试、打包与发布</span></span></code></pre></div><p><strong>优先级</strong>:01-14 每篇都建议看;15-19 按需(做什么功能看什么);20-22 上架前必看。</p><hr><h2 id="默认技术选择" tabindex="-1">默认技术选择 <a class="header-anchor" href="#默认技术选择" aria-label="Permalink to &quot;默认技术选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>选择</th><th>一句话理由</th></tr></thead><tbody><tr><td>平台</td><td>minSdk = 26 / target = 35</td><td>覆盖 95%+ 装机,同时拿到 Compose / NotificationChannel / 现代后台</td></tr><tr><td>主语言</td><td>Kotlin 2.0,K2 编译器</td><td>协程 / Flow 是一等公民,K2 显著提升编译速度</td></tr><tr><td>UI</td><td>Jetpack Compose BOM 1.7+ Material 3</td><td>不写 XML View;Strong Skipping / SharedElement / TextField2 已稳定</td></tr><tr><td>Activity</td><td>单 Activity + Navigation Compose</td><td>一棵树挂一个 Activity 上,扔掉 Fragment</td></tr><tr><td>DI</td><td>Hilt</td><td>注解 + KSP 编译期生成,默认答案</td></tr><tr><td>持久化</td><td>Room + DataStore</td><td>关系数据 Room,键值偏好 DataStore</td></tr><tr><td>网络</td><td>Retrofit + OkHttp + kotlinx.serialization</td><td><code>suspend</code> 一等公民,不写 RxJava</td></tr><tr><td>并发</td><td>协程 + Flow</td><td>结构化并发 + 取消传播</td></tr><tr><td>构建</td><td>Gradle KTS + Version Catalog + KSP</td><td>不写 Groovy,不写 KAPT</td></tr><tr><td>性能</td><td>Macrobenchmark + Baseline Profile</td><td>startup / scroll 可量化</td></tr><tr><td>发布</td><td>App Bundle (AAB) + Play Console</td><td>不讲 APK 直接分发</td></tr></tbody></table><p><strong>不覆盖</strong>:KMP / Java 主线 / XML View 主线 / Flutter / RN / NDK 深度。跨端见 [[flutterLearning]]。</p><hr><h2 id="持续演进的样例应用-notedx" tabindex="-1">持续演进的样例应用:NotedX <a class="header-anchor" href="#持续演进的样例应用-notedx" aria-label="Permalink to &quot;持续演进的样例应用:NotedX&quot;">​</a></h2><p>整个系列共享一个样例应用 <strong>NotedX</strong>(笔记 + 待办 + 图片附件 + 云同步),从第 05 篇起逐章长大,最终具备:</p><ul><li>单 Activity + Compose,Material 3 + edge-to-edge</li><li>笔记 / 待办 / 标签三个实体,Room + DataStore</li><li>Hilt DI,Retrofit + OkHttp 拉远端,kotlinx.serialization 解析</li><li>CameraX 拍照 + Photo Picker 选图 + MediaStore 写图片</li><li>WorkManager 周期同步,FCM 推送</li><li>App Bundle 签名上架 Play Internal Track,Baseline Profile 优化启动</li><li>Macrobenchmark 跑基准,R8 瘦身</li></ul><p>这套功能恰好覆盖一个真实应用的所有关键面:UI 重组成本(列表 + 输入)、持久化与远程同步、系统能力(相机 / 媒体 / 推送)、性能与发布。比 To-Do 更接近真实,比社交 App 又不被业务细节带偏。</p><p><strong>但 NotedX 不是每篇都强调</strong>——它是一根可以挂代码的线,不是这本书的主角。心智才是主角。</p><hr><h2 id="写作风格-强约束" tabindex="-1">写作风格(强约束) <a class="header-anchor" href="#写作风格-强约束" aria-label="Permalink to &quot;写作风格(强约束)&quot;">​</a></h2><ol><li>每篇开篇一句话压上核心 claim,不超 40 字。</li><li>章节标题用「一、二、三」,不用「机制定位 / 调参与验收」之类的学究腔。</li><li>段落不超过 150 字,长段落必拆。</li><li>强观点直接说。读者要的是判断,不是百科。</li><li>表格只用于真正需要对比的地方,不堆砌。</li><li>每篇结尾留一段&quot;踩坑&quot;,对应一个真实事故场景,不写&quot;建议注意&quot;这种废话。</li><li>不写多余的&quot;小结&quot;和&quot;过渡段&quot;。</li></ol>`,29)])])}const g=n(o,[["render",i]]);export{u as __pageData,g as default};
